changeSet.sql:
drop trigger if exists trg_song_enforce_resource_id_immutable on gmdb.song;
create trigger trg_song_enforce_resource_id_immutable
    before update of details on gmdb.song
    for each row
execute function gmdb.details_enforce_resource_id_immutable();

drop trigger if exists trg_song_default_resource_id on gmdb.song;
create trigger trg_song_default_resource_id
    before insert on gmdb.song
    for each row
execute function gmdb.details_default_resource_id();
